namespace sv_046f65d609254c5893718ef53fccfd88.Models;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@* Reusable message input: textarea + send/reply button *@

<div class="message-input d-flex gap-2 p-2 border-top">
    <textarea class="form-control" rows="2" placeholder="@Placeholder"
              @bind="text" @bind:event="oninput"
              @onkeydown="HandleKeyDown"></textarea>
    <button class="btn btn-primary align-self-end" disabled="@string.IsNullOrWhiteSpace(text)"
            @onclick="Send">@ButtonLabel</button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string text = string.Empty;

    private async Task Send()
    {
        if (string.IsNullOrWhiteSpace(text)) return;
        var msg = text.Trim();
        text = string.Empty;
        await OnSend.InvokeAsync(msg);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Send();
        }
    }
}

@using sv_046f65d609254c5893718ef53fccfd88.Models

@if (Reactions?.Count > 0)
{
    <div class="reaction-bar d-flex gap-1 mt-1">
        @foreach (var r in Reactions)
        {
            <button class="btn btn-sm btn-outline-secondary reaction-badge py-0 px-1"
                    title="@string.Join(", ", r.Users)"
                    @onclick="() => OnReactionClick.InvokeAsync(r.Emoji)">
                @r.Emoji @r.Users.Count
            </button>
        }
    </div>
}

@code {
    [Parameter] public List<Reaction>? Reactions { get; set; }
    [Parameter] public EventCallback<string> OnReactionClick { get; set; }
}

@using sv_046f65d609254c5893718ef53fccfd88.Models

<div class="message-item p-2 rounded @(IsHighlighted ? "bg-light" : "")"
     @onmouseenter="() => hovered = true" @onmouseleave="OnMouseLeave">
    <div class="d-flex justify-content-between align-items-start">
        <div>
            <strong>@Message.Author</strong>
            <small class="text-muted ms-2" title="@Message.SentAt.ToString("f")">@FormatRelativeTime(Message.SentAt)</small>
        </div>

        @if (hovered)
        {
            <div class="message-actions d-flex gap-1">
                <button class="btn btn-sm btn-outline-secondary py-0 px-1" @onclick="() => showEmojiPicker = !showEmojiPicker"
                        title="React">😊</button>
                @if (!HideReplyButton)
                {
                    <button class="btn btn-sm btn-outline-secondary py-0 px-1" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)"
                            title="Reply in thread">💬</button>
                }
            </div>
        }
    </div>

    <div class="mt-1">@Message.Content</div>

    <ReactionBar Reactions="Message.Reactions" OnReactionClick="HandleReaction" />

    @if (showEmojiPicker)
    {
        <div class="position-relative">
            <div class="position-absolute" style="z-index:10; bottom:0;">
                <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
            </div>
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="btn btn-sm btn-link text-decoration-none p-0 mt-1"
                @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public bool IsHighlighted { get; set; }
    [Parameter] public bool HideReplyButton { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool hovered;
    private bool showEmojiPicker;

    private async Task HandleReaction(string emoji)
    {
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private async Task HandleEmojiSelected(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private void OnMouseLeave()
    {
        hovered = false;
        showEmojiPicker = false;
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@using sv_046f65d609254c5893718ef53fccfd88.Models

<button class="list-group-item list-group-item-action d-flex flex-column align-items-start @(IsActive ? "active" : "")"
        @onclick="() => OnSelect.InvokeAsync(Channel.Id)">
    <div class="d-flex w-100 justify-content-between">
        <span class="fw-semibold text-truncate"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="badge bg-danger rounded-pill">@Channel.UnreadCount</span>
        }
    </div>
    @if (!string.IsNullOrWhiteSpace(Channel.Description))
    {
        <small class="@(IsActive ? "text-white-50" : "text-muted") text-truncate w-100">@TruncateDescription(Channel.Description)</small>
    }
</button>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelect { get; set; }

    private static string TruncateDescription(string desc)
        => desc.Length > 50 ? desc[..47] + "…" : desc;
}

@using sv_046f65d609254c5893718ef53fccfd88.Models

<div class="channel-sidebar d-flex flex-column h-100 border-end">
    <div class="p-3 border-bottom">
        <h6 class="mb-0 fw-bold">Channels</h6>
    </div>
    <div class="list-group list-group-flush overflow-auto flex-grow-1">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelect="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

@using sv_046f65d609254c5893718ef53fccfd88.Models

<div class="message-list d-flex flex-column flex-grow-1 overflow-auto p-3">
    @if (HasMore)
    {
        <div class="text-center mb-2">
            <button class="btn btn-sm btn-outline-secondary" disabled="@LoadingMore"
                    @onclick="OnLoadMore">
                @(LoadingMore ? "Loading…" : "Load older messages")
            </button>
        </div>
    }

    @foreach (var msg in Messages)
    {
        <MessageItem Message="msg"
                     ReplyCount="GetReplyCount(msg.Id)"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />
    }

    @if (Messages.Count == 0)
    {
        <div class="text-muted text-center my-auto">No messages yet. Start the conversation!</div>
    }
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool HasMore { get; set; }
    [Parameter] public bool LoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private int GetReplyCount(int messageId)
        => ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId)?.ReplyCount ?? 0;
}

@using sv_046f65d609254c5893718ef53fccfd88.Models

<div class="message-area d-flex flex-column h-100">
    @if (Channel is not null)
    {
        <div class="p-3 border-bottom">
            <h5 class="mb-0"># @Channel.Name</h5>
            <small class="text-muted">@Channel.Description</small>
        </div>

        <MessageList Messages="Messages"
                     ThreadSummaries="ThreadSummaries"
                     HasMore="HasMore"
                     LoadingMore="LoadingMore"
                     OnLoadMore="OnLoadMore"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />

        <MessageInput Placeholder="Message #@Channel.Name" OnSend="OnSendMessage" />
    }
    else
    {
        <div class="d-flex align-items-center justify-content-center flex-grow-1 text-muted">
            Select a channel to start chatting
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool HasMore { get; set; }
    [Parameter] public bool LoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
}

@using sv_046f65d609254c5893718ef53fccfd88.Models

<div class="thread-panel d-flex flex-column h-100 border-start">
    <div class="p-3 border-bottom d-flex justify-content-between align-items-center">
        <h6 class="mb-0 fw-bold">Thread</h6>
        <button class="btn btn-sm btn-outline-secondary" @onclick="OnClose">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="p-3 border-bottom bg-light">
            <MessageItem Message="RootMessage" HideReplyButton="true" OnReact="OnReact" />
        </div>

        <div class="flex-grow-1 overflow-auto p-3">
            @foreach (var reply in Replies)
            {
                <MessageItem Message="reply" HideReplyButton="true" OnReact="OnReact" />
            }

            @if (Replies.Count == 0)
            {
                <div class="text-muted text-center mt-3">No replies yet</div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread…" ButtonLabel="Reply" OnSend="OnSendReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
}

