@page "/chat"
@rendermode InteractiveServer

@using sv_046f65d609254c5893718ef53fccfd88.Components.Chat
@using sv_046f65d609254c5893718ef53fccfd88.Models

@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main">
        <MessageArea Channel="ActiveChannel"
                     Messages="messages"
                     ThreadSummaries="threadSummaries"
                     HasMore="hasMore"
                     LoadingMore="loadingMore"
                     OnLoadMore="LoadMoreMessages"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction"
                     OnSendMessage="SendMessage" />
    </div>

    @if (threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnSendReply="SendThreadReply"
                         OnClose="CloseThread"
                         OnReact="HandleReaction" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<ThreadSummary> threadSummaries = [];
    private int activeChannelId;
    private bool hasMore;
    private bool loadingMore;

    // Thread state
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    private Channel? ActiveChannel => channels.FirstOrDefault(c => c.Id == activeChannelId);

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();

        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        activeChannelId = channelId;
        messages = [];
        threadSummaries = [];
        CloseThread();

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messages = loaded;
        hasMore = loaded.Count == PageSize;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);
        await RefreshChannels();
    }

    private async Task LoadMoreMessages()
    {
        if (loadingMore) return;
        loadingMore = true;

        var older = await ChatService.GetMessagesAsync(activeChannelId, messages.Count, PageSize);
        messages.InsertRange(0, older);
        hasMore = older.Count == PageSize;
        loadingMore = false;

        BuildThreadSummaries();
    }

    private async Task SendMessage(string content)
    {
        var msg = await ChatService.SendMessageAsync(activeChannelId, content, null);
        messages.Add(msg);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to show updated reaction counts
        var refreshed = await ChatService.GetMessagesAsync(activeChannelId, 0, messages.Count);
        messages = refreshed;

        // Refresh thread if open
        if (threadRootMessage is not null)
        {
            threadReplies = await ChatService.GetThreadAsync(threadRootMessage.Id);
        }
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
    }

    private void CloseThread()
    {
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null) return;

        await ChatService.SendMessageAsync(activeChannelId, content, threadRootMessage.Id);
        threadReplies = await ChatService.GetThreadAsync(threadRootMessage.Id);

        BuildThreadSummaries();
    }

    private async Task RefreshChannels()
    {
        channels = await ChatService.GetChannelsAsync();
    }

    private void BuildThreadSummaries()
    {
        // Build summaries from messages that have replies referencing them
        var roots = messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .Select(g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)))
            .ToList();

        threadSummaries = roots;
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

::deep .message-item {
    transition: background-color 0.15s;
}

::deep .message-item:hover {
    background-color: rgba(0, 0, 0, 0.03);
}

::deep .reaction-badge {
    font-size: 0.8rem;
    line-height: 1.4;
}

::deep .emoji-picker button {
    font-size: 1.2rem;
    padding: 0.15rem 0.35rem;
}

::deep .channel-sidebar .list-group-item {
    border-radius: 0;
    border-left: 0;
    border-right: 0;
}

